node <<'EOF'
const api = require('/opt/homebrew/lib/node_modules/9router/src/cli/api/client.js');
const https = require('https');

function head(url) {
  return new Promise((resolve) => {
    const req = https.request(url, { method: 'HEAD', timeout: 10000 }, res => {
      resolve({ status: res.statusCode, location: res.headers.location });
    });
    req.on('error', e => resolve({ status: 0, error: e.message }));
    req.on('timeout', () => { req.destroy(); resolve({ status: 0, error: 'timeout' }); });
    req.end();
  });
}

(async () => {
  for (let i = 0; i < 20; i++) {
    const st = await api.getTunnelStatus();
    const t = st.data.tunnel;
    console.log(`poll ${i}`, { enabled: t.enabled, running: t.running, tunnelUrl: t.tunnelUrl, publicUrl: t.publicUrl });
    if (t.running && t.tunnelUrl) {
      const direct = await head(t.tunnelUrl + '/');
      const pub = await head(t.publicUrl + '/');
      console.log('direct', direct);
      console.log('public', pub);
      if (direct.status === 307 || direct.status === 200) {
        console.log('DIRECT_OK');
      }
      if (pub.status === 307 || pub.status === 200) {
        console.log('PUBLIC_OK');
        process.exit(0);
      }
    }
    await new Promise(r => setTimeout(r, 2000));
  }
  console.log('GIVE_UP');
  process.exit(2);
})().catch(e => { console.error(e); process.exit(1); });
EOF

