node <<'EOF'
const api = require('/opt/homebrew/lib/node_modules/9router/src/cli/api/client.js');
const https = require('https');

function get(url, path='/api/health') {
  return new Promise((resolve) => {
    const u = new URL(path, url);
    const req = https.get(u, { timeout: 8000 }, res => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => resolve({ status: res.statusCode, data: data.slice(0,200) }));
    });
    req.on('error', e => resolve({ status: 0, error: e.message }));
    req.on('timeout', () => { req.destroy(); resolve({ status: 0, error: 'timeout' }); });
  });
}

(async () => {
  console.log('disable first...');
  console.log(JSON.stringify(await api.disableTunnel()));
  await new Promise(r => setTimeout(r, 2000));

  console.log('enable (may take up to ~60s for health)...');
  const t0 = Date.now();
  const on = await api.enableTunnel();
  console.log('enable after', Date.now()-t0, 'ms', JSON.stringify(on, null, 2));

  for (let i = 0; i < 30; i++) {
    const st = await api.getTunnelStatus();
    const t = st.data.tunnel;
    const direct = t.tunnelUrl ? await get(t.tunnelUrl) : {status:0};
    const pub = t.publicUrl ? await get(t.publicUrl) : {status:0};
    console.log(`poll ${i}`, {
      enabled: t.enabled, running: t.running,
      tunnelUrl: t.tunnelUrl,
      direct: direct.status || direct.error,
      public: pub.status || pub.error,
    });
    if (t.running && (direct.status === 200) && (pub.status === 200)) {
      console.log('ALL_GOOD', t.publicUrl);
      process.exit(0);
    }
    await new Promise(r => setTimeout(r, 2000));
  }
  process.exit(2);
})().catch(e => { console.error(e); process.exit(1); });
EOF

